# Crear el diccionario de preguntas
preguntas = {}
for letra, palabras in banco.items():
    preguntas[letra] = []
    for palabra in palabras:
        pregunta = {
            "tipo": "empieza",
            "definicion": f"Empieza por {letra}: Palabra relacionada con {palabra.lower()}",
            "respuesta": palabra,
            "usada": False
        }
        preguntas[letra].append(pregunta)
    print(f"  {letra}: {len(preguntas[letra])} preguntas")

# Guardar el archivo
with open("static/pasapalabra/preguntas.json", "w", encoding="utf-8") as f:
    json.dump(preguntas, f, ensure_ascii=False, indent=2)

